162→export const getCountNotificationsService = async (userId) => {
163→    const { data, error } = await supabase.rpc('get_unread_notification_count', {
164→        p_user_id: userId,
165→    });
166→
167→    if (error) {
168→        console.error('get_unread_notification_count rpc error:', error.message);
169→        throw { status: 500, error: 'error fetching count in notifications table' };
170→    }
171→
172→    return { count: data ?? 0 };
173→};
