136→export const addBookmarkService = async(userId, journalId) =>{
137→    if(!userId){
138→        throw new AppError(400, 'userId is undefined');
139→    }
140→    if(!journalId){
141→        throw new AppError(400, 'journalId is undefined');
142→    }
143→
144→    const {data:checkExisting, error: errorCheckExisting} = await supabase
145→    .from('bookmarks')
146→    .select('*')
147→    .eq('user_id',userId)
148→    .eq('journal_id', journalId)
149→    .maybeSingle()
150→
151→    if(errorCheckExisting){
152→        console.error('supabase error while checking the existing bookmarks', errorCheckExisting.message);
153→        throw new AppError(500, 'supabase error while checking the existing bookmarks');
154→    }
155→
156→    if(!checkExisting){
157→        const {error: errorAddBookmark} = await supabase
158→        .from('bookmarks')
159→        .insert({user_id: userId, journal_id: journalId})
160→
161→        if(errorAddBookmark){
162→            console.error('supabase error while adding bookmark', errorAddBookmark.message);
163→            throw new AppError(500, 'supabase error while adding bookmark');
164→        }
165→
166→        return {message: 'success'};
167→    } else {
168→        const {error: errorDeletingBookmark} = await supabase
169→        .from('bookmarks')
170→        .delete()
171→        .eq('user_id', userId)
172→        .eq('journal_id', journalId)
173→
174→        if(errorDeletingBookmark){
