 15→
 16→const TOTAL_STEPS = 5;
 17→
 18→const slideVariants = {
 19→    enter: (direction) => ({
 20→        x: direction > 0 ? 80 : -80,
 21→        opacity: 0,
 22→    }),
 23→    center: {
 24→        x: 0,
 25→        opacity: 1,
 26→    },
 27→    exit: (direction) => ({
 28→        x: direction > 0 ? -80 : 80,
 29→        opacity: 0,
 30→    }),
 31→};
 32→
 33→const slideTransition = {
 34→    type: 'spring',
 35→    stiffness: 350,
 36→    damping: 32,
 37→    mass: 0.8,
 38→};
