200→export const getCommentsService = async (chapterId, paragraphIndex) => {
201→    if (!chapterId) {
202→        throw { status: 400, error: 'chapterId is required' };
203→    }
204→
205→    let query = supabase
206→        .from('story_comments')
207→        .select(`*, users(id, name, image_url, username, badge)`)
208→        .eq('chapter_id', chapterId)
209→        .is('parent_id', null)
210→        .order('created_at', { ascending: true })
211→        .limit(50);
212→
213→    if (paragraphIndex !== undefined && paragraphIndex !== null) {
214→        query = query.eq('paragraph_index', parseInt(paragraphIndex));
215→    }
216→
217→    const { data: comments, error } = await query;
218→
219→    if (error) {
220→        console.error('supabase error fetching comments:', error.message);
221→        throw { status: 500, error: 'failed to fetch comments' };
222→    }
223→
224→    // Fetch replies for all top-level comments
225→    if (comments && comments.length > 0) {
226→        const commentIds = comments.map(c => c.id);
227→        const { data: replies, error: replyError } = await supabase
228→            .from('story_comments')
229→            .select(`*, users(id, name, image_url, username, badge)`)
230→            .in('parent_id', commentIds)
231→            .order('created_at', { ascending: true })
232→            .limit(200);
233→
234→        if (!replyError && replies) {
235→            const replyMap = {};
236→            replies.forEach(r => {
237→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
238→                replyMap[r.parent_id].push(r);
239→            });
240→            comments.forEach(c => {
241→                c.replies = replyMap[c.id] || [];
242→            });
243→        }
244→    }
245→
246→    return comments || [];
247→};
