 25→export const getUserByUsernameService = async(username) => {
 26→    if(!username || typeof username !== 'string'){
 27→        throw {status: 400, message: 'username is required'};
 28→    }
 29→
 30→    const normalizedUsername = username.trim().toLowerCase();
 31→
 32→    const { data: users, error: userError } = await supabase
 33→        .from('users')
 34→        .select(USER_PROFILE_SELECT)
 35→        .ilike('username', normalizedUsername)
 36→        .limit(1);
 37→
 38→    if(userError){
 39→        console.error('supabase error fetching user by username:', userError.message);
 40→        throw {status: 500, message: 'supabase error fetching user by username'};
 41→    }
 42→
 43→    if(!users || users.length === 0){
 44→        throw {status: 404, message: 'user not found'};
 45→    }
 46→
 47→    const user = decorateProfileUser(users[0]);
 48→
 49→    const followerCountPromise = supabase
 50→        .from('follows')
 51→        .select('id', {count: 'exact', head: true})
 52→        .eq('following_id', user.id);
 53→
 54→    const followingCountPromise = supabase
 55→        .from('follows')
 56→        .select('id', {count: 'exact', head: true})
 57→        .eq('follower_id', user.id);
 58→
 59→    const [followerCountResult, followingCountResult] = await Promise.all([
 60→        followerCountPromise, followingCountPromise
 61→    ]);
 62→
 63→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
 64→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
 65→
 66→    if(errorFollowerCount || errorFollowingCount){
 67→        console.error('supabase error fetching follow counts:', errorFollowerCount || errorFollowingCount);
 68→    }
 69→
 70→    return {
 71→        userData: [user],
 72→        followerCount: followerCount || 0,
 73→        followingCount: followingCount || 0
 74→    };
 75→}
